-- =========================================================
-- Seed 60 CDE Indicators into indicator_library
-- =========================================================
-- Run this in your Supabase SQL Editor (Dashboard > SQL Editor)
-- Safe to run multiple times - skips existing indicators
-- =========================================================

-- Step 1: Ensure code column has a unique constraint for ON CONFLICT
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_indexes
    WHERE tablename = 'indicator_library' AND indexdef LIKE '%code%' AND indexdef LIKE '%UNIQUE%'
  ) THEN
    -- Check if there's already a unique constraint
    IF NOT EXISTS (
      SELECT 1 FROM information_schema.table_constraints tc
      JOIN information_schema.constraint_column_usage ccu ON tc.constraint_name = ccu.constraint_name
      WHERE tc.table_name = 'indicator_library' AND ccu.column_name = 'code' AND tc.constraint_type = 'UNIQUE'
    ) THEN
      CREATE UNIQUE INDEX IF NOT EXISTS idx_indicator_library_code_unique ON public.indicator_library (code);
      RAISE NOTICE 'Created unique index on indicator_library.code';
    END IF;
  END IF;
END $$;

-- Step 2: Disable RLS temporarily for this session (SQL Editor runs as postgres)
-- This allows us to insert system indicators without RLS restrictions

